import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ tours, setTours, editingTour, setEditingTour }) => {
  const { user } = useAuth();
  // 這裡新增了 price 和 duration 欄位，符合你的 Tour Model
  const [formData, setFormData] = useState({ 
    title: '', 
    description: '', 
    price: '', 
    duration: '' 
  });

  useEffect(() => {
    if (editingTour) {
      setFormData({
        title: editingTour.title,
        description: editingTour.description,
        price: editingTour.price,
        duration: editingTour.duration || '',
      });
    } else {
      setFormData({ title: '', description: '', price: '', duration: '' });
    }
  }, [editingTour]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingTour) {
        // 修改 API 路徑為 /api/tours
        const response = await axiosInstance.put(`/api/tours/${editingTour._id}`, formData, {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setTours(tours.map((tour) => (tour._id === response.data._id ? response.data : tour)));
        alert('Tour updated successfully!');
      } else {
        // 新增 API 路徑為 /api/tours
        const response = await axiosInstance.post('/api/tours', formData, {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setTours([...tours, response.data]);
        alert('New Tour added!');
      }
      setEditingTour(null);
      setFormData({ title: '', description: '', price: '', duration: '' });
    } catch (error) {
      console.error(error);
      alert('Failed to save tour package.');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 shadow-md rounded mb-6 border-t-4 border-blue-500">
      <h2 className="text-2xl font-bold mb-4 text-gray-800">
        {editingTour ? 'Edit Tour Package' : 'Create New Tour Package'}
      </h2>

      {/* 行程名稱 */}
      <input
        type="text"
        placeholder="Tour Title (e.g. Great Ocean Road 12-A)"
        value={formData.title}
        onChange={(e) => setFormData({ ...formData, title: e.target.value })}
        className="w-full mb-4 p-2 border rounded focus:outline-none focus:ring-2 focus:ring-blue-400"
        required
      />

      {/* 價格欄位 (新增) */}
      <input
        type="number"
        placeholder="Price (AUD)"
        value={formData.price}
        onChange={(e) => setFormData({ ...formData, price: e.target.value })}
        className="w-full mb-4 p-2 border rounded focus:outline-none focus:ring-2 focus:ring-blue-400"
        required
      />

      {/* 行程天數 */}
      <input
        type="text"
        placeholder="Duration (e.g. 4 Days / 3 Nights)"
        value={formData.duration}
        onChange={(e) => setFormData({ ...formData, duration: e.target.value })}
        className="w-full mb-4 p-2 border rounded focus:outline-none focus:ring-2 focus:ring-blue-400"
      />

      {/* 行程描述 */}
      <textarea
        placeholder="Tour Description"
        value={formData.description}
        onChange={(e) => setFormData({ ...formData, description: e.target.value })}
        className="w-full mb-4 p-2 border rounded focus:outline-none focus:ring-2 focus:ring-blue-400"
        rows="3"
      />

      <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold p-2 rounded transition duration-200">
        {editingTour ? 'Update Tour Package' : 'Add to Catalog'}
      </button>

      {editingTour && (
        <button 
          onClick={() => setEditingTour(null)}
          className="w-full mt-2 bg-gray-300 text-gray-700 p-2 rounded hover:bg-gray-400"
        >
          Cancel Edit
        </button>
      )}
    </form>
  );
};

export default TourForm;
